import React, { useCallback, useEffect, useRef, useState } from 'react';
import type { FeedbackCategory, FeedbackWidgetConfig, WidgetState, ChatMessage } from './types';
import { useVoiceRecorder } from './useVoiceRecorder';
import { useEventTracker } from './useEventTracker';
import { useFeedbackApi } from './useFeedbackApi';
import { useChatApi } from './useChatApi';
import { useScreenshotAnnotation } from './useScreenshotAnnotation';

const CATEGORIES: { value: FeedbackCategory; label: string; icon: string }[] = [
  { value: 'bug', label: 'Bug', icon: '🐛' },
  { value: 'suggestion', label: 'Suggestion', icon: '💡' },
  { value: 'confusion', label: 'Confused', icon: '❓' },
  { value: 'praise', label: 'Praise', icon: '👍' },
];

const POSITION_CLASSES: Record<string, React.CSSProperties> = {
  'bottom-right': { bottom: 24, right: 24 },
  'bottom-left': { bottom: 24, left: 24 },
  'top-right': { top: 24, right: 24 },
  'top-left': { top: 24, left: 24 },
};

const INACTIVITY_TIMEOUT_MS = 5 * 60 * 1000;

function formatTime(ms: number): string {
  const secs = Math.floor(ms / 1000);
  const mins = Math.floor(secs / 60);
  const remainingSecs = secs % 60;
  return `${mins}:${remainingSecs.toString().padStart(2, '0')}`;
}

// --- SVG Icons (inline to avoid dependencies) ---

function MicIcon({ size = 16 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M12 2a3 3 0 0 0-3 3v7a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3Z" />
      <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
      <line x1="12" y1="19" x2="12" y2="22" />
    </svg>
  );
}

function ChatIcon({ size = 16 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
    </svg>
  );
}

function CameraIcon({ size = 16 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M14.5 4h-5L7 7H4a2 2 0 0 0-2 2v9a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2V9a2 2 0 0 0-2-2h-3l-2.5-3z" />
      <circle cx="12" cy="13" r="3" />
    </svg>
  );
}

function SendIcon({ size = 16 }: { size?: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="currentColor">
      <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z" />
    </svg>
  );
}

// --- Main Widget ---

export function FeedbackWidget({ appId, apiUrl, user, position = 'bottom-right', apiKey, chatApiUrl }: FeedbackWidgetConfig) {
  const [widgetState, setWidgetState] = useState<WidgetState>('idle');
  const [isExpanded, setIsExpanded] = useState(false);
  const [category, setCategory] = useState<FeedbackCategory>('suggestion');
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [chatInput, setChatInput] = useState('');
  const [isVoiceRecordingInChat, setIsVoiceRecordingInChat] = useState(false);

  const sessionStartRef = useRef<number>(0);
  const sessionIdRef = useRef<string | null>(null);
  const inactivityTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const chatMessagesEndRef = useRef<HTMLDivElement>(null);

  const recorder = useVoiceRecorder();
  const chatVoiceRecorder = useVoiceRecorder();
  const tracker = useEventTracker();
  const api = useFeedbackApi(apiUrl, apiKey);
  const chat = useChatApi(chatApiUrl || '', sessionIdRef.current, appId, apiKey);

  const chatEnabled = Boolean(chatApiUrl);

  const uploadScreenshotForAnnotation = useCallback(async (blob: Blob, index: number): Promise<string> => {
    const { uploadUrl, key } = await api.getUploadUrl('screenshot', index);
    await fetch(uploadUrl, { method: 'PUT', headers: { 'Content-Type': 'image/png' }, body: blob });
    return key;
  }, [api]);

  const annotation = useScreenshotAnnotation(uploadScreenshotForAnnotation);

  // Auto-scroll chat to bottom when new messages arrive
  useEffect(() => {
    chatMessagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chat.messages]);

  // When an annotation is captured, send it as a chat message
  useEffect(() => {
    if (annotation.lastAnnotation && widgetState === 'chatting') {
      const ann = annotation.lastAnnotation;
      const description = `[Pointed at ${ann.elementInfo.tag}${ann.elementInfo.text ? `: "${ann.elementInfo.text.slice(0, 80)}"` : ''} at (${ann.coordinates.x}, ${ann.coordinates.y}) on ${ann.pageUrl}]`;
      chat.sendMessage(description, [{
        type: 'annotation',
        annotation: ann,
      }]);
    }
  // Only trigger when lastAnnotation changes
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [annotation.lastAnnotation]);

  // Inactivity auto-stop for voice recording
  const resetInactivityTimer = useCallback(() => {
    if (inactivityTimerRef.current) clearTimeout(inactivityTimerRef.current);
    inactivityTimerRef.current = setTimeout(() => {
      if (widgetState === 'recording') {
        handleStopRef.current();
      }
    }, INACTIVITY_TIMEOUT_MS);
  }, [widgetState]);

  const handleStopRef = useRef<() => void>(() => {});

  useEffect(() => {
    if (widgetState !== 'recording') return;
    const onActivity = () => resetInactivityTimer();
    window.addEventListener('click', onActivity, true);
    window.addEventListener('scroll', onActivity, true);
    window.addEventListener('keydown', onActivity, true);
    window.addEventListener('mousemove', onActivity, true);
    resetInactivityTimer();
    return () => {
      window.removeEventListener('click', onActivity, true);
      window.removeEventListener('scroll', onActivity, true);
      window.removeEventListener('keydown', onActivity, true);
      window.removeEventListener('mousemove', onActivity, true);
      if (inactivityTimerRef.current) clearTimeout(inactivityTimerRef.current);
    };
  }, [widgetState, resetInactivityTimer]);

  // --- Handlers ---

  const handleStartRecording = useCallback(async () => {
    try {
      setErrorMessage(null);
      const sid = await api.createSession(appId, user);
      sessionIdRef.current = sid;
      await recorder.startRecording();
      tracker.startTracking();
      sessionStartRef.current = Date.now();
      setWidgetState('recording');
      setIsExpanded(false);
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : 'Failed to start recording');
      setWidgetState('error');
    }
  }, [api, appId, user, recorder, tracker]);

  const handleStartChat = useCallback(async () => {
    try {
      setErrorMessage(null);
      const sid = await api.createSession(appId, user);
      sessionIdRef.current = sid;
      tracker.startTracking();
      sessionStartRef.current = Date.now();
      chat.reset();
      setWidgetState('chatting');

      // Send initial greeting from bot
      setTimeout(() => {
        chat.sendMessage('__init__');
      }, 300);
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : 'Failed to start chat session');
      setWidgetState('error');
    }
  }, [api, appId, user, tracker, chat]);

  const handleStopRecording = useCallback(async () => {
    try {
      setWidgetState('submitting');
      setIsExpanded(true);
      const audioBlob = await recorder.stopRecording();
      tracker.stopTracking();
      const duration = Math.round((Date.now() - sessionStartRef.current) / 1000);
      if (audioBlob && audioBlob.size > 0) {
        await api.uploadAudio(audioBlob);
      }
      await api.submitSession({ category, events: tracker.getEvents(), duration });
      setWidgetState('submitted');
      setTimeout(() => { setWidgetState('idle'); setIsExpanded(false); }, 3000);
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : 'Failed to submit feedback');
      setWidgetState('error');
    }
  }, [recorder, tracker, api, category]);

  const handleEndChat = useCallback(async () => {
    try {
      setWidgetState('submitting');
      tracker.stopTracking();
      const duration = Math.round((Date.now() - sessionStartRef.current) / 1000);

      // Ask the bot to summarize the conversation
      const summary = await chat.summarize();

      await api.submitSession({
        category: summary?.category || category,
        events: tracker.getEvents(),
        duration,
        chatMessages: chat.messages,
        annotations: annotation.annotations,
        chatSummary: summary || undefined,
      });

      setWidgetState('submitted');
      setTimeout(() => { setWidgetState('idle'); setIsExpanded(false); chat.reset(); }, 3000);
    } catch (err) {
      setErrorMessage(err instanceof Error ? err.message : 'Failed to submit feedback');
      setWidgetState('error');
    }
  }, [tracker, api, category, chat, annotation.annotations]);

  handleStopRef.current = handleStopRecording;

  const handleSendChatMessage = useCallback(async () => {
    const text = chatInput.trim();
    if (!text) return;
    setChatInput('');
    await chat.sendMessage(text);
  }, [chatInput, chat]);

  const handleVoiceInChat = useCallback(async () => {
    if (isVoiceRecordingInChat) {
      // Stop recording and transcribe
      setIsVoiceRecordingInChat(false);
      const blob = await chatVoiceRecorder.stopRecording();
      if (blob && blob.size > 0) {
        // Upload audio for transcription and send as message
        // For now, we'll send a placeholder that the Lambda will transcribe
        try {
          const { uploadUrl, key } = await api.getUploadUrl('audio-chunk', Date.now());
          await fetch(uploadUrl, { method: 'PUT', headers: { 'Content-Type': blob.type }, body: blob });
          chat.sendMessage('[Voice message - transcribing...]', [{
            type: 'voice-transcript',
            key,
          }]);
        } catch {
          setErrorMessage('Failed to upload voice message');
        }
      }
    } else {
      // Start recording
      setIsVoiceRecordingInChat(true);
      await chatVoiceRecorder.startRecording();
    }
  }, [isVoiceRecordingInChat, chatVoiceRecorder, api, chat]);

  const handleAnnotate = useCallback(() => {
    // Stay in 'chatting' state — the annotation overlay manages its own visibility
    annotation.startAnnotation();
  }, [annotation]);

  const handleReset = useCallback(() => {
    setWidgetState('idle');
    setErrorMessage(null);
    setIsExpanded(false);
    setChatInput('');
    chat.reset();
  }, [chat]);

  const positionStyle = POSITION_CLASSES[position] || POSITION_CLASSES['bottom-right'];

  // --- Render helpers ---

  const renderChatMessages = () => (
    <div style={{
      flex: 1, overflowY: 'auto', padding: '8px 12px',
      display: 'flex', flexDirection: 'column', gap: 8,
      maxHeight: 280, minHeight: 120,
    }}>
      {chat.messages
        .filter((m: ChatMessage) => m.content !== '__init__')
        .map((msg: ChatMessage) => (
        <div key={msg.id} style={{
          display: 'flex',
          justifyContent: msg.role === 'user' ? 'flex-end' : 'flex-start',
        }}>
          <div style={{
            maxWidth: '85%',
            padding: '8px 12px',
            borderRadius: msg.role === 'user' ? '12px 12px 2px 12px' : '12px 12px 12px 2px',
            backgroundColor: msg.role === 'user' ? '#0D9488' : '#F3F4F6',
            color: msg.role === 'user' ? '#fff' : '#1F2937',
            fontSize: 13,
            lineHeight: 1.5,
            wordBreak: 'break-word',
          }}>
            {msg.content}
            {msg.attachments?.some(a => a.type === 'annotation') && (
              <div style={{
                marginTop: 4, fontSize: 11, opacity: 0.8,
                display: 'flex', alignItems: 'center', gap: 4,
              }}>
                <CameraIcon size={11} /> Screenshot attached
              </div>
            )}
          </div>
        </div>
      ))}
      {chat.isLoading && (
        <div style={{ display: 'flex', justifyContent: 'flex-start' }}>
          <div style={{
            padding: '8px 16px', borderRadius: '12px 12px 12px 2px',
            backgroundColor: '#F3F4F6', color: '#9CA3AF', fontSize: 13,
          }}>
            <span style={{ animation: 'feedback-pulse 1.2s ease-in-out infinite' }}>Thinking...</span>
          </div>
        </div>
      )}
      <div ref={chatMessagesEndRef} />
    </div>
  );

  const renderChatInput = () => (
    <div style={{
      padding: '8px 12px', borderTop: '1px solid #E5E7EB',
      display: 'flex', gap: 6, alignItems: 'flex-end',
    }}>
      {/* Annotate button */}
      <button
        onClick={handleAnnotate}
        title="Point to something on the page"
        style={{
          padding: 6, borderRadius: 6, border: '1px solid #E5E7EB',
          backgroundColor: '#fff', color: '#6B7280', cursor: 'pointer',
          display: 'flex', alignItems: 'center', flexShrink: 0,
        }}
      >
        <CameraIcon size={16} />
      </button>

      {/* Voice-in-chat button */}
      <button
        onClick={handleVoiceInChat}
        title={isVoiceRecordingInChat ? 'Stop recording' : 'Record voice message'}
        style={{
          padding: 6, borderRadius: 6,
          border: `1px solid ${isVoiceRecordingInChat ? '#EF4444' : '#E5E7EB'}`,
          backgroundColor: isVoiceRecordingInChat ? '#FEF2F2' : '#fff',
          color: isVoiceRecordingInChat ? '#EF4444' : '#6B7280',
          cursor: 'pointer', display: 'flex', alignItems: 'center', flexShrink: 0,
          animation: isVoiceRecordingInChat ? 'feedback-pulse 1.5s ease-in-out infinite' : 'none',
        }}
      >
        <MicIcon size={16} />
      </button>

      {/* Text input */}
      <input
        type="text"
        value={chatInput}
        onChange={(e) => setChatInput(e.target.value)}
        onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendChatMessage(); } }}
        placeholder="What's on your mind? Navigate to the page first..."
        style={{
          flex: 1, padding: '8px 12px', borderRadius: 8,
          border: '1px solid #E5E7EB', fontSize: 13,
          outline: 'none', fontFamily: 'inherit',
        }}
        disabled={chat.isLoading}
      />

      {/* Send button */}
      <button
        onClick={handleSendChatMessage}
        disabled={!chatInput.trim() || chat.isLoading}
        style={{
          padding: 6, borderRadius: 6, border: 'none',
          backgroundColor: chatInput.trim() ? '#0D9488' : '#E5E7EB',
          color: chatInput.trim() ? '#fff' : '#9CA3AF',
          cursor: chatInput.trim() ? 'pointer' : 'default',
          display: 'flex', alignItems: 'center', flexShrink: 0,
        }}
      >
        <SendIcon size={16} />
      </button>
    </div>
  );

  // --- Render states ---

  // Minimized recording indicator
  if (widgetState === 'recording' && !isExpanded) {
    return (
      <div data-feedback-widget style={{ ...positionStyle, position: 'fixed', zIndex: 99999 }}>
        <div
          style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: '8px 14px', borderRadius: 20,
            backgroundColor: 'rgba(239, 68, 68, 0.95)', color: '#fff',
            fontFamily: 'system-ui, sans-serif', fontSize: 13, fontWeight: 600,
            boxShadow: '0 2px 8px rgba(239, 68, 68, 0.3)', cursor: 'pointer',
            animation: 'feedback-pulse 2s ease-in-out infinite',
          }}
          onClick={() => setIsExpanded(true)}
        >
          <span style={{ width: 8, height: 8, borderRadius: 4, backgroundColor: '#fff' }} />
          {formatTime(recorder.elapsedMs)}
          <button
            onClick={(e) => { e.stopPropagation(); handleStopRecording(); }}
            style={{
              marginLeft: 4, padding: '2px 8px', borderRadius: 10,
              border: '1px solid rgba(255,255,255,0.5)',
              backgroundColor: 'rgba(255,255,255,0.2)', color: '#fff',
              fontSize: 11, fontWeight: 600, cursor: 'pointer',
            }}
          >
            Stop
          </button>
        </div>
        <style>{`@keyframes feedback-pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.85; } }`}</style>
      </div>
    );
  }

  // Minimized chat indicator
  if (widgetState === 'chatting' && !isExpanded) {
    return (
      <div data-feedback-widget style={{ ...positionStyle, position: 'fixed', zIndex: 99999 }}>
        <div
          style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: '8px 14px', borderRadius: 20,
            backgroundColor: 'rgba(13, 148, 136, 0.95)', color: '#fff',
            fontFamily: 'system-ui, sans-serif', fontSize: 13, fontWeight: 600,
            boxShadow: '0 2px 8px rgba(13, 148, 136, 0.3)', cursor: 'pointer',
          }}
          onClick={() => setIsExpanded(true)}
        >
          <ChatIcon size={14} />
          Chat ({chat.messages.filter((m: ChatMessage) => m.content !== '__init__').length} msgs)
          <button
            onClick={(e) => { e.stopPropagation(); handleEndChat(); }}
            style={{
              marginLeft: 4, padding: '2px 8px', borderRadius: 10,
              border: '1px solid rgba(255,255,255,0.5)',
              backgroundColor: 'rgba(255,255,255,0.2)', color: '#fff',
              fontSize: 11, fontWeight: 600, cursor: 'pointer',
            }}
          >
            End
          </button>
        </div>
      </div>
    );
  }

  // Idle state — floating button
  if ((widgetState === 'idle' || widgetState === 'annotating') && !isExpanded) {
    return (
      <div data-feedback-widget style={{ ...positionStyle, position: 'fixed', zIndex: 99999 }}>
        <button
          onClick={() => setIsExpanded(true)}
          style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: '10px 18px', borderRadius: 24, border: 'none',
            backgroundColor: '#0D9488', color: '#fff',
            fontSize: 14, fontWeight: 600, fontFamily: 'system-ui, sans-serif',
            cursor: 'pointer', boxShadow: '0 4px 12px rgba(13, 148, 136, 0.3)',
            transition: 'transform 0.15s, box-shadow 0.15s',
          }}
          onMouseEnter={(e) => { e.currentTarget.style.transform = 'scale(1.05)'; e.currentTarget.style.boxShadow = '0 6px 16px rgba(13, 148, 136, 0.4)'; }}
          onMouseLeave={(e) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = '0 4px 12px rgba(13, 148, 136, 0.3)'; }}
        >
          <ChatIcon size={18} />
          Give Feedback
        </button>
      </div>
    );
  }

  // --- Expanded panel ---
  const headerColor =
    widgetState === 'recording' ? '#EF4444' :
    widgetState === 'chatting' ? '#0D9488' :
    widgetState === 'submitted' ? '#10B981' :
    '#0D9488';

  const headerTitle =
    widgetState === 'recording' ? `Recording ${formatTime(recorder.elapsedMs)}` :
    widgetState === 'chatting' ? 'Feedback Chat' :
    widgetState === 'submitting' ? 'Submitting...' :
    widgetState === 'submitted' ? 'Thank you!' :
    'Feedback';

  return (
    <div
      data-feedback-widget
      style={{
        ...positionStyle, position: 'fixed', zIndex: 99999,
        width: widgetState === 'chatting' ? 360 : 320,
        borderRadius: 16, backgroundColor: '#fff',
        boxShadow: '0 8px 32px rgba(0, 0, 0, 0.15)',
        fontFamily: 'system-ui, -apple-system, sans-serif',
        overflow: 'hidden',
        display: 'flex', flexDirection: 'column',
        maxHeight: widgetState === 'chatting' ? '70vh' : 'auto',
      }}
    >
      {/* Header */}
      <div style={{
        padding: '14px 16px', backgroundColor: headerColor, color: '#fff',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        flexShrink: 0,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          {widgetState === 'recording' && (
            <span style={{
              width: 10, height: 10, borderRadius: 5,
              backgroundColor: '#fff', display: 'inline-block',
              animation: 'feedback-pulse 1.5s ease-in-out infinite',
            }} />
          )}
          {widgetState === 'chatting' && <ChatIcon size={16} />}
          <span style={{ fontSize: 14, fontWeight: 600 }}>{headerTitle}</span>
        </div>
        {widgetState !== 'submitting' && widgetState !== 'submitted' && (
          <button
            onClick={() => {
              if (widgetState === 'recording' || widgetState === 'chatting') {
                setIsExpanded(false);
              } else {
                setIsExpanded(false);
                handleReset();
              }
            }}
            style={{
              background: 'none', border: 'none', color: '#fff',
              cursor: 'pointer', fontSize: 18, lineHeight: 1, padding: '0 4px',
            }}
          >
            {(widgetState === 'recording' || widgetState === 'chatting') ? '\u2212' : '\u00d7'}
          </button>
        )}
      </div>

      {/* Body */}
      <div style={{ padding: widgetState === 'chatting' ? 0 : 16, flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Error state */}
        {(widgetState === 'error' || recorder.error) && (
          <div style={{ padding: widgetState === 'chatting' ? 12 : 0, marginBottom: 12 }}>
            <div style={{
              padding: '10px 12px', borderRadius: 8,
              backgroundColor: '#FEF2F2', color: '#991B1B',
              fontSize: 13, lineHeight: 1.4,
            }}>
              {errorMessage || recorder.error || chat.error}
            </div>
            <button onClick={handleReset} style={{
              marginTop: 8, padding: '6px 14px', borderRadius: 6,
              border: '1px solid #D1D5DB', backgroundColor: '#fff',
              color: '#374151', fontSize: 13, cursor: 'pointer',
            }}>
              Try Again
            </button>
          </div>
        )}

        {/* Submitted state */}
        {widgetState === 'submitted' && (
          <div style={{ textAlign: 'center', padding: '8px 0' }}>
            <p style={{ fontSize: 14, color: '#374151', margin: 0 }}>
              Your feedback has been recorded and will be reviewed.
            </p>
          </div>
        )}

        {/* Submitting state */}
        {widgetState === 'submitting' && (
          <div style={{ textAlign: 'center', padding: '8px 0' }}>
            <p style={{ fontSize: 14, color: '#6B7280', margin: 0 }}>Uploading your feedback...</p>
          </div>
        )}

        {/* Idle: mode selection + category */}
        {widgetState === 'idle' && !recorder.error && !errorMessage && (
          <>
            <p style={{ fontSize: 13, color: '#6B7280', margin: '0 0 12px 0', lineHeight: 1.4 }}>
              {chatEnabled
                ? 'Chat or record while you navigate — we track which page you\'re on automatically. Click around the app to show us exactly where something needs attention.'
                : 'Hit record and navigate the app — we\'ll track which page you\'re on. Talk through what you see as you click around.'}
            </p>

            {/* Category pills */}
            <div style={{ marginBottom: 14 }}>
              <label style={{ fontSize: 12, color: '#9CA3AF', fontWeight: 500, display: 'block', marginBottom: 6 }}>
                Category
              </label>
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                {CATEGORIES.map((cat) => (
                  <button
                    key={cat.value}
                    onClick={() => setCategory(cat.value)}
                    style={{
                      padding: '5px 12px', borderRadius: 16,
                      border: `2px solid ${category === cat.value ? '#0D9488' : '#E5E7EB'}`,
                      backgroundColor: category === cat.value ? '#F0FDFA' : '#fff',
                      color: category === cat.value ? '#0D9488' : '#6B7280',
                      fontSize: 13, fontWeight: 500, cursor: 'pointer',
                      transition: 'all 0.15s',
                    }}
                  >
                    {cat.icon} {cat.label}
                  </button>
                ))}
              </div>
            </div>

            {/* Mode buttons */}
            <div style={{ display: 'flex', gap: 8 }}>
              {chatEnabled && (
                <button
                  onClick={handleStartChat}
                  style={{
                    flex: 1, padding: '10px 0', borderRadius: 8, border: 'none',
                    backgroundColor: '#0D9488', color: '#fff',
                    fontSize: 14, fontWeight: 600, cursor: 'pointer',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
                    transition: 'background-color 0.15s',
                  }}
                  onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#0F766E')}
                  onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#0D9488')}
                >
                  <ChatIcon size={16} />
                  Chat
                </button>
              )}
              <button
                onClick={handleStartRecording}
                style={{
                  flex: 1, padding: '10px 0', borderRadius: 8, border: 'none',
                  backgroundColor: '#EF4444', color: '#fff',
                  fontSize: 14, fontWeight: 600, cursor: 'pointer',
                  display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
                  transition: 'background-color 0.15s',
                }}
                onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = '#DC2626')}
                onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = '#EF4444')}
              >
                <MicIcon size={16} />
                {chatEnabled ? 'Voice' : 'Start Recording'}
              </button>
            </div>
          </>
        )}

        {/* Recording mode */}
        {widgetState === 'recording' && (
          <>
            <p style={{ fontSize: 11, color: '#9CA3AF', margin: '0 0 8px 0', lineHeight: 1.4, fontStyle: 'italic' }}>
              Navigate around — we're tracking where you are.
            </p>
            <div style={{
              padding: '8px 12px', borderRadius: 8,
              backgroundColor: '#F9FAFB', marginBottom: 12,
              fontSize: 12, color: '#6B7280',
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
                <span style={{ fontWeight: 600, color: '#374151' }}>Page:</span>
                <span style={{ fontFamily: 'monospace' }}>{tracker.getCurrentContext().route}</span>
              </div>
              {tracker.getCurrentContext().viewportSection && (
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <span style={{ fontWeight: 600, color: '#374151' }}>Section:</span>
                  <span>{tracker.getCurrentContext().viewportSection}</span>
                </div>
              )}
            </div>

            <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap', marginBottom: 12 }}>
              {CATEGORIES.map((cat) => (
                <button
                  key={cat.value}
                  onClick={() => setCategory(cat.value)}
                  style={{
                    padding: '3px 10px', borderRadius: 12,
                    border: `1.5px solid ${category === cat.value ? '#0D9488' : '#E5E7EB'}`,
                    backgroundColor: category === cat.value ? '#F0FDFA' : '#fff',
                    color: category === cat.value ? '#0D9488' : '#9CA3AF',
                    fontSize: 12, cursor: 'pointer',
                  }}
                >
                  {cat.icon} {cat.label}
                </button>
              ))}
            </div>

            <button
              onClick={handleStopRecording}
              style={{
                width: '100%', padding: '10px 0', borderRadius: 8, border: 'none',
                backgroundColor: '#374151', color: '#fff',
                fontSize: 14, fontWeight: 600, cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,
              }}
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
                <rect x="6" y="6" width="12" height="12" rx="2" />
              </svg>
              Stop &amp; Submit
            </button>
          </>
        )}

        {/* Chat mode */}
        {widgetState === 'chatting' && (
          <>
            {renderChatMessages()}
            {renderChatInput()}
            <div style={{
              padding: '6px 12px', borderTop: '1px solid #F3F4F6',
              display: 'flex', justifyContent: 'flex-end',
            }}>
              <button
                onClick={handleEndChat}
                style={{
                  padding: '5px 14px', borderRadius: 6, border: 'none',
                  backgroundColor: '#374151', color: '#fff',
                  fontSize: 12, fontWeight: 600, cursor: 'pointer',
                }}
              >
                End &amp; Submit
              </button>
            </div>
          </>
        )}
      </div>

      <style>{`
        @keyframes feedback-pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
}
