import { useCallback, useRef, useState } from 'react';
import type { ScreenshotAnnotation } from './types';

interface UseScreenshotAnnotationReturn {
  isAnnotating: boolean;
  startAnnotation: () => void;
  cancelAnnotation: () => void;
  /** The most recently captured annotation (reset on next startAnnotation) */
  lastAnnotation: ScreenshotAnnotation | null;
  /** All annotations captured during this session */
  annotations: ScreenshotAnnotation[];
}

function getElementSelector(el: Element): string {
  if (el.id) return `#${el.id}`;
  const parts: string[] = [];
  let current: Element | null = el;
  let depth = 0;
  while (current && depth < 4) {
    let selector = current.tagName.toLowerCase();
    if (current.id) {
      parts.unshift(`#${current.id}`);
      break;
    }
    const meaningful = Array.from(current.classList).filter(
      (c) => !c.includes(':') && !c.match(/^(p|m|w|h|flex|grid|text|bg|border|rounded|shadow)-/),
    );
    if (meaningful.length > 0) {
      selector += `.${meaningful.slice(0, 2).join('.')}`;
    }
    parts.unshift(selector);
    current = current.parentElement;
    depth++;
  }
  return parts.join(' > ');
}

/**
 * Hook for screenshot annotation mode. When activated, overlays a semi-transparent
 * layer on the page. User clicks to select a point, and we capture:
 * - Click coordinates
 * - DOM element info at the click point
 * - A screenshot of the viewport (as a data URL blob)
 */
export function useScreenshotAnnotation(
  uploadScreenshot: (blob: Blob, index: number) => Promise<string>,
): UseScreenshotAnnotationReturn {
  const [isAnnotating, setIsAnnotating] = useState(false);
  const [lastAnnotation, setLastAnnotation] = useState<ScreenshotAnnotation | null>(null);
  const [annotations, setAnnotations] = useState<ScreenshotAnnotation[]>([]);
  const overlayRef = useRef<HTMLDivElement | null>(null);
  const cleanupRef = useRef<(() => void) | null>(null);

  const captureScreenshot = useCallback(async (): Promise<Blob | null> => {
    // Hide the overlay temporarily for the screenshot
    if (overlayRef.current) overlayRef.current.style.display = 'none';

    try {
      // Use the browser's native screenshot API if available, otherwise canvas fallback
      if ('mediaDevices' in navigator && 'getDisplayMedia' in navigator.mediaDevices) {
        // Canvas-based viewport capture (no permission prompt needed in some contexts)
        // Fall through to canvas approach
      }

      // Canvas-based approach: capture the visible viewport
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return null;

      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;

      // Draw a white background
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Use svg foreignObject to render HTML to canvas
      const svgData = `
        <svg xmlns="http://www.w3.org/2000/svg" width="${canvas.width}" height="${canvas.height}">
          <foreignObject width="100%" height="100%">
            <div xmlns="http://www.w3.org/1999/xhtml">
              ${new XMLSerializer().serializeToString(document.documentElement)}
            </div>
          </foreignObject>
        </svg>`;

      const img = new Image();
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);

      return new Promise((resolve) => {
        img.onload = () => {
          ctx.drawImage(img, 0, 0);
          URL.revokeObjectURL(url);
          canvas.toBlob((blob) => resolve(blob), 'image/png', 0.8);
        };
        img.onerror = () => {
          URL.revokeObjectURL(url);
          // Fallback: just create a simple placeholder
          ctx.fillStyle = '#f0f0f0';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.fillStyle = '#666';
          ctx.font = '16px system-ui';
          ctx.fillText(`Screenshot of ${window.location.pathname}`, 20, 40);
          ctx.fillText(`Viewport: ${canvas.width}x${canvas.height}`, 20, 65);
          canvas.toBlob((blob) => resolve(blob), 'image/png', 0.8);
        };
        img.src = url;
      });
    } finally {
      if (overlayRef.current) overlayRef.current.style.display = '';
    }
  }, []);

  const startAnnotation = useCallback(() => {
    setIsAnnotating(true);
    setLastAnnotation(null);

    // Create overlay
    const overlay = document.createElement('div');
    overlay.setAttribute('data-feedback-annotation-overlay', 'true');
    Object.assign(overlay.style, {
      position: 'fixed',
      inset: '0',
      zIndex: '100000',
      backgroundColor: 'rgba(0, 0, 0, 0.15)',
      cursor: 'crosshair',
      transition: 'background-color 0.2s',
    });

    // Tooltip that follows the cursor
    const tooltip = document.createElement('div');
    Object.assign(tooltip.style, {
      position: 'fixed',
      padding: '6px 12px',
      borderRadius: '6px',
      backgroundColor: 'rgba(13, 148, 136, 0.95)',
      color: '#fff',
      fontSize: '13px',
      fontWeight: '600',
      fontFamily: 'system-ui, sans-serif',
      pointerEvents: 'none',
      zIndex: '100001',
      boxShadow: '0 2px 8px rgba(0,0,0,0.2)',
      display: 'none',
    });
    tooltip.textContent = 'Click to annotate this area';
    document.body.appendChild(tooltip);

    // Highlight element under cursor
    const highlight = document.createElement('div');
    Object.assign(highlight.style, {
      position: 'fixed',
      border: '2px solid rgba(13, 148, 136, 0.7)',
      backgroundColor: 'rgba(13, 148, 136, 0.1)',
      borderRadius: '4px',
      pointerEvents: 'none',
      zIndex: '100001',
      transition: 'all 0.1s',
      display: 'none',
    });
    document.body.appendChild(highlight);

    overlayRef.current = overlay;

    const onMouseMove = (e: MouseEvent) => {
      // Position tooltip
      tooltip.style.display = 'block';
      tooltip.style.left = `${e.clientX + 16}px`;
      tooltip.style.top = `${e.clientY + 16}px`;

      // Highlight element under cursor (peek through the overlay)
      overlay.style.pointerEvents = 'none';
      const elementUnder = document.elementFromPoint(e.clientX, e.clientY);
      overlay.style.pointerEvents = '';

      if (elementUnder && !elementUnder.closest('[data-feedback-widget]') && !elementUnder.closest('[data-feedback-annotation-overlay]')) {
        const rect = elementUnder.getBoundingClientRect();
        highlight.style.display = 'block';
        highlight.style.left = `${rect.left}px`;
        highlight.style.top = `${rect.top}px`;
        highlight.style.width = `${rect.width}px`;
        highlight.style.height = `${rect.height}px`;
      } else {
        highlight.style.display = 'none';
      }
    };

    const onClick = async (e: MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();

      // Get the element under the click (peek through overlay)
      overlay.style.pointerEvents = 'none';
      const elementUnder = document.elementFromPoint(e.clientX, e.clientY);
      overlay.style.pointerEvents = '';

      if (!elementUnder) {
        cleanup();
        return;
      }

      const selector = getElementSelector(elementUnder);
      const text = (elementUnder.textContent || '').trim().slice(0, 200);
      const tag = elementUnder.tagName.toLowerCase();

      // Capture screenshot
      const screenshotBlob = await captureScreenshot();
      let screenshotKey = '';

      if (screenshotBlob) {
        try {
          screenshotKey = await uploadScreenshot(screenshotBlob, annotations.length);
        } catch {
          // Screenshot upload failed — continue without it
        }
      }

      const annotation: ScreenshotAnnotation = {
        screenshotKey,
        coordinates: { x: e.clientX, y: e.clientY },
        elementInfo: {
          selector,
          tag,
          text,
          id: elementUnder.id || undefined,
          className: elementUnder.className?.toString().slice(0, 200) || undefined,
        },
        pageUrl: window.location.href,
        viewport: { width: window.innerWidth, height: window.innerHeight },
      };

      setLastAnnotation(annotation);
      setAnnotations(prev => [...prev, annotation]);

      cleanup();
    };

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        cleanup();
      }
    };

    const cleanup = () => {
      overlay.removeEventListener('mousemove', onMouseMove);
      overlay.removeEventListener('click', onClick);
      window.removeEventListener('keydown', onKeyDown);
      overlay.remove();
      tooltip.remove();
      highlight.remove();
      overlayRef.current = null;
      setIsAnnotating(false);
    };

    cleanupRef.current = cleanup;

    overlay.addEventListener('mousemove', onMouseMove);
    overlay.addEventListener('click', onClick);
    window.addEventListener('keydown', onKeyDown);

    document.body.appendChild(overlay);
  }, [captureScreenshot, uploadScreenshot, annotations.length]);

  const cancelAnnotation = useCallback(() => {
    cleanupRef.current?.();
  }, []);

  return { isAnnotating, startAnnotation, cancelAnnotation, lastAnnotation, annotations };
}
