import { useCallback, useRef, useState } from 'react';
import type { ChatMessage, ChatSummary } from './types';

interface UseChatApiReturn {
  messages: ChatMessage[];
  isLoading: boolean;
  error: string | null;
  sendMessage: (content: string, attachments?: ChatMessage['attachments']) => Promise<void>;
  summarize: () => Promise<ChatSummary | null>;
  reset: () => void;
}

let messageCounter = 0;
function generateMessageId(): string {
  messageCounter += 1;
  return `msg-${Date.now()}-${messageCounter}`;
}

/**
 * Hook for communicating with the sevaro-feedback-chat Lambda.
 * Manages the conversation state and sends messages to the AI chatbot.
 */
export function useChatApi(chatApiUrl: string, sessionId: string | null, appId: string, apiKey?: string): UseChatApiReturn {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const messagesRef = useRef<ChatMessage[]>([]);
  const sessionIdRef = useRef(sessionId);
  sessionIdRef.current = sessionId;

  const sendMessage = useCallback(async (content: string, attachments?: ChatMessage['attachments']) => {
    if (!sessionIdRef.current) {
      setError('No active session — start a feedback session first');
      return;
    }

    const userMessage: ChatMessage = {
      id: generateMessageId(),
      role: 'user',
      content,
      timestamp: new Date().toISOString(),
      attachments,
    };

    const updated = [...messagesRef.current, userMessage];
    messagesRef.current = updated;
    setMessages(updated);
    setIsLoading(true);
    setError(null);

    try {
      const chatHeaders: Record<string, string> = { 'Content-Type': 'application/json' };
      if (apiKey) chatHeaders['x-api-key'] = apiKey;

      const res = await fetch(`${chatApiUrl}/chat`, {
        method: 'POST',
        headers: chatHeaders,
        body: JSON.stringify({
          sessionId: sessionIdRef.current,
          appId,
          message: content,
          attachments,
          history: messagesRef.current.map(m => ({ role: m.role, content: m.content })),
          context: {
            pageUrl: window.location.href,
            pageTitle: document.title,
            viewport: { width: window.innerWidth, height: window.innerHeight },
          },
        }),
      });

      if (!res.ok) {
        const errBody = await res.json().catch(() => ({ error: `HTTP ${res.status}` }));
        throw new Error(errBody.error || `Chat request failed: ${res.status}`);
      }

      const data = await res.json();

      const assistantMessage: ChatMessage = {
        id: generateMessageId(),
        role: 'assistant',
        content: data.reply,
        timestamp: new Date().toISOString(),
      };

      const withReply = [...messagesRef.current, assistantMessage];
      messagesRef.current = withReply;
      setMessages(withReply);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to send message');
    } finally {
      setIsLoading(false);
    }
  }, [chatApiUrl, appId, apiKey]);

  const summarize = useCallback(async (): Promise<ChatSummary | null> => {
    if (!sessionIdRef.current || messagesRef.current.length === 0) return null;

    try {
      const sumHeaders: Record<string, string> = { 'Content-Type': 'application/json' };
      if (apiKey) sumHeaders['x-api-key'] = apiKey;

      const res = await fetch(`${chatApiUrl}/chat/summarize`, {
        method: 'POST',
        headers: sumHeaders,
        body: JSON.stringify({
          sessionId: sessionIdRef.current,
          appId,
          messages: messagesRef.current.map(m => ({
            role: m.role,
            content: m.content,
            attachments: m.attachments,
          })),
        }),
      });

      if (!res.ok) return null;
      return await res.json() as ChatSummary;
    } catch {
      return null;
    }
  }, [chatApiUrl, appId, apiKey]);

  const reset = useCallback(() => {
    messagesRef.current = [];
    setMessages([]);
    setIsLoading(false);
    setError(null);
  }, []);

  return { messages, isLoading, error, sendMessage, summarize, reset };
}
